import React, { useState } from 'react';
import {
  Diamond,
  Eye,
  EyeOff,
  Mail,
  Lock,
  User,
  Phone,
  AlertCircle
} from 'lucide-react';
import authService from './services/authService';

const Login = ({ onLogin }) => {
  const [isSignUp, setIsSignUp] = useState(false);
  const [loading, setLoading] = useState(false);

  const [showPassword, setShowPassword] = useState(false);
  const [showConfirmPassword, setShowConfirmPassword] = useState(false);

  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    password: '',
    confirmPassword: ''
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    setError('');
    setMessage('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    setMessage('');

    try {
      if (isSignUp) {
        if (formData.password !== formData.confirmPassword) {
          setError('Passwords do not match');
          setLoading(false);
          return;
        }

        const response = await authService.register({
          name: formData.name,
          email: formData.email,
          password: formData.password,
          phone: formData.phone
        });

        if (response.success) {
          setIsSignUp(false);
          setMessage('Registration successful. Please log in.');

          // ✅ FIX: CLEAR EVERYTHING (email + password included)
          setFormData({
            name: '',
            email: '',
            phone: '',
            password: '',
            confirmPassword: ''
          });

          setShowPassword(false);
          setShowConfirmPassword(false);
        } else {
          setError(response.error || 'Registration failed');
        }

      } else {
        const response = await authService.login({
          email: formData.email,
          password: formData.password
        });

        if (response.success) {
          onLogin(response.data);
        } else {
          setError(response.error || 'Login failed');
        }
      }

    } catch (err) {
      setError(err.response?.data?.error || 'Something went wrong. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">

      <div className="w-full max-w-md bg-white/5 backdrop-blur-xl p-8 rounded-3xl border border-white/10">

        <h2 className="text-white text-center text-2xl font-bold mb-6">
          {isSignUp ? 'Create Account' : 'Welcome Back'}
        </h2>

        {/* MESSAGE */}
        {message && (
          <div className="mb-4 p-3 bg-green-500/10 text-green-400 rounded-xl text-sm">
            {message}
          </div>
        )}

        {error && (
          <div className="mb-4 p-3 bg-red-500/10 text-red-400 rounded-xl text-sm flex gap-2 items-center">
            <AlertCircle className="w-4 h-4" />
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">

          {/* NAME */}
          {isSignUp && (
            <div>
              <label className="text-sm text-gray-300">Full Name</label>
              <input
                name="name"
                value={formData.name}
                onChange={handleChange}
                placeholder="Enter your full name"
                className="w-full p-3 rounded-xl bg-slate-900 text-white placeholder-gray-500"
              />
            </div>
          )}

          {/* EMAIL */}
          <div>
            <label className="text-sm text-gray-300">Email</label>
            <input
              name="email"
              value={formData.email}
              onChange={handleChange}
              placeholder="Enter your email"
              className="w-full p-3 rounded-xl bg-slate-900 text-white placeholder-gray-500"
            />
          </div>

          {/* PHONE */}
          {isSignUp && (
            <div>
              <label className="text-sm text-gray-300">Phone</label>
              <input
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                placeholder="09XXXXXXXXX"
                className="w-full p-3 rounded-xl bg-slate-900 text-white placeholder-gray-500"
              />
            </div>
          )}

          {/* PASSWORD */}
          <div className="relative">
            <label className="text-sm text-gray-300">Password</label>
            <input
              type={showPassword ? 'text' : 'password'}
              name="password"
              value={formData.password}
              onChange={handleChange}
              placeholder="Enter password"
              className="w-full p-3 pr-10 rounded-xl bg-slate-900 text-white placeholder-gray-500"
            />

            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-3 top-9 text-gray-400"
            >
              {showPassword ? <EyeOff /> : <Eye />}
            </button>
          </div>

          {/* CONFIRM PASSWORD */}
          {isSignUp && (
            <div className="relative">
              <label className="text-sm text-gray-300">Confirm Password</label>
              <input
                type={showConfirmPassword ? 'text' : 'password'}
                name="confirmPassword"
                value={formData.confirmPassword}
                onChange={handleChange}
                placeholder="Confirm password"
                className="w-full p-3 pr-10 rounded-xl bg-slate-900 text-white placeholder-gray-500"
              />

              <button
                type="button"
                onClick={() => setShowConfirmPassword(!showConfirmPassword)}
                className="absolute right-3 top-9 text-gray-400"
              >
                {showConfirmPassword ? <EyeOff /> : <Eye />}
              </button>
            </div>
          )}

          {/* SUBMIT */}
          <button
            disabled={loading}
            className="w-full p-3 bg-gradient-to-r from-cyan-500 to-purple-500 text-white rounded-xl font-bold"
          >
            {loading ? 'Loading...' : isSignUp ? 'Create Account' : 'Sign In'}
          </button>

        </form>

        {/* TOGGLE */}
        <p className="text-center text-gray-400 mt-5">
          {isSignUp ? 'Already have an account?' : "Don't have an account?"}
          <button
            className="text-cyan-400 ml-2"
            onClick={() => {
              setIsSignUp(!isSignUp);
              setError('');
              setMessage('');
            }}
          >
            {isSignUp ? 'Sign In' : 'Create account'}
          </button>
        </p>

      </div>
    </div>
  );
};

export default Login;
